inline bool DecodeJson(std::string& out) {
    static constexpr unsigned char invalid = 255;
    unsigned char table[256];
    std::fill(table, table + 256, invalid);
    for (unsigned char c = 'A'; c <= 'Z'; ++c) table[c] = c - 'A';
    for (unsigned char c = 'a'; c <= 'z'; ++c) table[c] = c - 'a' + 26;
    for (unsigned char c = '0'; c <= '9'; ++c) table[c] = c - '0' + 52;
    table[static_cast<unsigned char>('+')] = 62;
    table[static_cast<unsigned char>('/')] = 63;

    out.clear();
    out.reserve(std::char_traits<char>::length(kJsonBase64) * 3 / 4);
    int val = 0;
    int bits = -8;
    for (unsigned char c : std::string_view(kJsonBase64)) {
        if (c == '=') break;
        const unsigned char decoded = table[c];
        if (decoded == invalid) return false;
        val = (val << 6) | decoded;
        bits += 6;
        if (bits >= 0) {
            out.push_back(static_cast<char>((val >> bits) & 0xff));
            bits -= 8;
        }
    }
    if (out.size() >= 3 && static_cast<unsigned char>(out[0]) == 0xEF &&
        static_cast<unsigned char>(out[1]) == 0xBB &&
        static_cast<unsigned char>(out[2]) == 0xBF) out.erase(0, 3);
    return true;
}

